.TaskerOverallStyleSheet { display: none; } /* Name of Style Sheet, do not use to style HTML */


/* Variables section start */
$min-height-standard: 55px;

/* 
Note: how the mixin math is working:
<expression> + <expression> adds the first expression's value to the second's 
Pass in a negitve value to reduce the minium standard height
*/
@mixin adjustMinHeight($heightAdjust) {
  min-height: $heightAdjust + $min-height-standard;
}

@mixin adjustTop($heightAdjust) {
  top: $heightAdjust + $min-height-standard;
}
/* Variables section end */

.modal-content {
  top: 25px;
}

.modal-header, .modal-body {
  padding: 5px 15px;
}

/* needed for modal to flex widgets */
.dtech-modal-relative {
  height: calc(100vh - 20vh);
  position: relative;
}

.dtech-force-column-grow {
  display: flex !important;
  flex-direction: column !important;
  flex-grow: 1 !important;
  overflow: hidden !important;
}

/* 2.7.2 | 2022-01-12 | mmcc | DFCT0010728 - Modal Scheduled Tasks shows title data with an ellipsis
flexbox ellipsis start 
*/
.dtech-container-menu-row {
  align-items: center;
  column-gap: 5px;
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
}

.dtech-col-cell-flex1-middle {
  flex: 1 1 auto;
  vertical-align: middle;
}

.dtech-col-1-flex0-middle {
  flex: 0 0 auto;
  vertical-align: middle;
}

.dtech-col-2-flex-row-w40per-ellipsis {
  display: flex;
  flex-direction: row;
  width: 40%;

  .title-ellipsised {
    flex: 1 2 auto;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.dtech-col-3-flex-row-w45per-ellipsis {
  display: flex;
  flex-direction: row;
  width: 45%;

  .title-ellipsised {
    flex: 1 2 auto;
    padding: 10px 10px 10px 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}

.dtech-col-7-flex-row-end {
  display: flex;
  flex-direction: row;
  justify-content: flex-end;
}

.detech-col-8-flex0-middle-w30px {
  flex: 0 0 auto;
  vertical-align: middle;
  width: 30px;
}
/* flexbox ellipsis end */

/* 2.7.1 | 2021-12-15 | mmcc | DFCT0010716 - On Tabs (OU, Task) the icons did not align correctly with text at the top of the page */
.dtech-align-menu-text-icons {
  padding: 10px 0;
  vertical-align: middle;
}


div.breadcrumbs-container {
  padding-bottom: 0 !important;
  padding-top: 0 !important;
}

.dtech-tabpane-no-header-stick-posabso {
  border-radius: 0;
  border-top-width: 0;
  bottom: 5px;
  left: 10px;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 10px;
  top: 15px;
}

.dtech-tabpane-with-header-stick-posabso {
  border-radius: 0;
  border-top-width: 0;
  bottom: 5px;
  left: 10px;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 10px;
  /* top: 90px; */
  @include adjustTop(15px);
}

.dtech-tabpane-with-header-ribbon1-stick-top {
  /* top: 105px; */
  @include adjustTop(30px);
}

.dtech-tabpane-with-header-ribbon2-stick-top {
  /* top: 120px; */
  @include adjustTop(45px);
}

.dtech-tabpane-with-tabs-stick-posabso {
  border-radius: 0;
  border-top-width: 0;
  bottom: 5px;
  left: 10px;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 10px;
  /* top: $min-height-standard */
  @include adjustTop(0px);
}

.dtech-topstick-posabso {
  border-radius: 0;
  bottom: 0;
  left: 0;
  margin: 0;
  overflow: hidden;
  position: absolute;
  right: 0;
  top: 0;
}

.dtech-topstick-posabso-rl-active {
  position: absolute;
  top: 0;
  bottom: 0;
/* not using these hence the -rl-active
  right: 0;
  left: 0; */
  margin: 0;
}

.dtech-panel-heading-min-height-standard {  
  /*min-height: 75px;*/
  @include adjustMinHeight(0px);
  padding: 5px 15px;
}

.dtech-tabs-min-height-standard {  
  /* min-height: 60px; */
  @include adjustMinHeight(-15px); 
}

/* STRY0121805 - this setting uses flex box row with wrap and center for the header row*/
/* STRY0126833 - override left padding */
.dtech-header-row{
  display: flex;
  flex-flow: row nowrap;
  justify-content:center;
  align-items:start;
  padding: 0 0 0 0;
}
/* STRY0121805 - this setting uses flex box row with wrap and center for the counter row*/
.dtech-count-row{
  display: flex;
  flex-flow: row wrap;
  justify-content:center;
  align-items:center;
}
/* STRY0121805 - this sets the width for all of the count items */
.dtech-count-column {
  /* width: 230px; */
  padding-right: 20px;
  padding-bottom: 10px;
}

/* STRY0121805 - this sets the bottom padding menu items */
.dtech-header-column {
  padding-top: 15px;
  padding-bottom: 10px;
}
.dtech-header-column-search {
  padding: 15px 0px 10px 30px;
}
/* STRY0121339 moved into global as it is used in Tasker Header Menu Wdiget and the Tasker Home Widget */
.dtech-header-menu-tab {/*Tab Styling*/
  display: inline-block;
  /* needed height to get border outside the svg*/
  height: 42px;
  margin: 0 0 -1px;
/* NOTE: Shawn requested what is below, need to get the anchor tag to take up it's full space for this to work as the padding is pushing the anchor down without increasing the size of the row 
  padding: 15px 5px; */
  padding: 0px 15px 0px 0px;
  border-radius: 5px;
  font-weight: 400;
  text-align: center;
  color: rgba(0, 0, 0, 1);
  cursor: pointer;
}

.dtech-header-menu-tab > a {
  height: 42px;
  padding: 10px;
  border-radius: 5px;
}

.dtech-header-menu-tab > a:hover {/*Blue line on Hover*/
  background-color: rgba(217, 237, 247, 1);
}

.dtech-header-menu-tab:focus {/*Blue line on Hover*/
  outline: 2px solid rgba(20, 146, 230, 1); 
  border-radius: 5px;
}

/* GoJS popover start */
#popoverWrapper {
  display: none;
  position: absolute;
  z-index: 1000;
}

#popoverWrapperList {
  display: none;
  position: absolute;
  z-index: 1100;
}

.dtech-popover-container-avatar {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  height: 365px;
  padding: 30px 20px 20px 20px;
  position: absolute;
  width: 400px;
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-popover-list-outer-container-lg {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  /* height: 365px; not needed since flex */
  display: flex;
  flex-flow: column nowrap;
  min-height: 100px;
  padding: 10px 20px;
  position: absolute;
  width: 250px; /* was 200px when font-size was 14px */
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-arrow-up:before {
  border-bottom: 10px solid $tasker-popover-arrow-color;
  border-left: 10px solid transparent;
  border-right: 10px solid transparent;
  content: '';
  height: 0;
  left: calc(100% / 2 - 10px);
  position: absolute;
  /* right: 50%; */
  top: -10px;
  width: 0;
  z-index: 2;
}

.dtech-arrow-up:after {
  border-bottom: 12px solid rgba(0, 0, 0, 0.1);
  border-left: 12px solid transparent;
  border-right: 12px solid transparent;
  content: '';
  height: 0;
  left: calc(100% /2 - 12px);
  position: absolute;
  /* right: 49%; */
  top: -12px; 
  width: 0;
  z-index: 1;
}

.dtech-popover-list-outer-container-md {
  background-color: $tasker-popover-container-avatar-color;
  border-radius: 5px;
  /* height: 365px; not needed since flex */
  display: flex;
  flex-flow: column nowrap;
  min-height: 40px;
  /* min-width: 165px; */
  padding: 10px 20px;
  position: absolute;
  /* width: 200px; */
  width: max-content;
  
  box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -webkit-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
  -moz-box-shadow: 0px 0px 20px 0px rgba(0, 0, 0, 0.25);
}

.dtech-popover-list-main-container {
  flex-flow: row nowrap;
  display: flex;
  flex: 1;
  max-height: 290px;
  overflow-y: auto;
}

.dtech-popover-list-spinner-content {
  align-self: center;
  flex: 1 1 auto;
  text-align: center;
}

.dtech-popover-list-footer-content {
  margin-left: 3.2rem; /* match width of dtech-avatar-round-* */
  margin-top: 20px; /* li has margin-bottom 10px for a total of 30px */
}

.dtech-footer-row-sticky {
  bottom: 20px;
  margin-top: 20px;
  position: absolute;
  width: calc(100% - 40px);
}

.dtech-opacity-50 {
  opacity: 0.5;
}

.dtech-avatar-text-standard-14 {
  color: $tasker-text-standard-color;
  font-size: 14px;
}

.dtech-avatar-text-standard-16 {
  color: $tasker-text-standard-color;
  font-size: 16px;
}

.dtech-avatar-link {
  color: $tasker-link-color;
  font-size: 16px;
  text-decoration-line: underline;
  text-decoration-color: $tasker-link-color;
  text-decoration-style: solid;
}

/* profile photo start */
.dtech-avatar-round-32rem {
  cursor: default;
  height: 3.2rem;
  width: 3.2rem;
}

.dtech-avatar-round-64rem {
  cursor: default;
  height: 6.4rem;
  width: 6.4rem;
}

.dtech-avatar-bg-color {
  background-color: $tasker-avatar-bg-color !important;
  background-repeat: no-repeat !important; 
}

.dtech-avatar-bg-color-transparent {
  background-color: transparent !important;
}

/* profile photo end */
/* GoJS popover end */

/* DFCT0010887 & DFCT0010911 Template Pages start */
/*.dtech-fill-section {
    position: relative;
    overflow-y: auto;
    height: calc(100vh - 350px);
}*/
/* DFCT0010887 & DFCT0010911 Template Pages end */

#dtech-list-1 .selected {
  color: $taskerdatatable-selected-row-text;
  background-color: $taskerdatatable-selected-row-bg;
}

.dtech-box {
  display: flex;
}

/* Must be a descendant of the class dtech-box */
.dtech-box .dtech-push-right {
  margin-left: auto!important;
}

.dtech-disabled {
  pointer-events: none;
  cursor: default;
  opacity: 50%;
}

.dtech-enabled {
  pointer-events: auto;
  cursor: pointer;
  opacity: 100%;
}

.dtech-flex-grow-0 {
  flex-grow: 0;
}

.dtech-flex-grow-1-shrink-1-basis-0 {
  flex-grow: 1;
  flex-shrink: 1;
  flex-basis: 0;
}

.dtech-flex-grow-1-shrink-0-basis-auto {
  flex-grow: 1;
  flex-shrink: 0;
  flex-basis: auto;
}

.dtech-flex-grow-0dot2-shrink-1-basis-0p {
  flex: .2;
  /* Yields
  flex-grow: 0.2;
  flex-shrink: 1;
  flex-basis: 0%;
  */
}
.dtech-flex-grow-0dot4-shrink-1-basis-0p {
  flex: .4;
  /* Yields
  flex-grow: 0.4;
  flex-shrink: 1;
  flex-basis: 0%;
  */
}

.dtech-flex-grow-0dot6-shrink-1-basis-0p {
  flex: .6;
  /* Yields
  flex-grow: 0.6;
  flex-shrink: 1;
  flex-basis: 0%;
  */
}

.dtech-flex-grow-0dot8-shrink-1-basis-0p {
  flex: .8;
  /* Yields
  flex-grow: 0.8;
  flex-shrink: 1;
  flex-basis: 0%;
  */
}

.dtech-flex-shrink-0 {
  flex-shrink: 0;
}

.dtech-h-50vh {
  height: 50vh;
}

.dtech-margin-all-5 {
  margin: 5px;
}

.dtech-margin-bottom-inherit {
  margin-bottom: inherit;
}

.dtech-margin-bottom-0 {
  margin-bottom: 0;
}

.dtech-margin-top-4px {
  margin-top: 4px;
}

.dtech-margin-top-5px {
  margin-top: 5px;
}

.dtech-max-width-fit-content {
  max-width: fit-content;
}

.dtech-overflow-auto {
  overflow: auto;
}

.dtech-overflow-auto-gutter-stable {
  /* margin-right: 5px; */
  overflow: auto;
  scrollbar-gutter: stable;
}

.dtech-overflow-auto-pad-right-15-gutter-stable {
  overflow: auto;
  padding-right: 15px;
  scrollbar-gutter: stable;
}

.dtech-overflow-hidden {
  overflow: hidden;
}

.dtech-pad-all-0 {
  padding: 0;
}

.dtech-pad-all-10 {
  padding: 10px;
}
 
.dtech-pad-all-5-15 {
  padding: 5px 15px;
