/* STRY0121805 */
.dtech-pad-bottom-5 {
  padding-bottom: 5px;
}
.dtech-pad-bottom-10 {
  padding-bottom: 10px;
}

.dtech-pad-left-0 {
  padding-left: 0;
}

.dtech-pad-left-5 {
  padding-left: 5px;
}

.dtech-pad-left-10 {
  padding-left: 10px;
}

.dtech-pad-right-0 {
