  padding-top: 5px;
}

.dtech-pad-top-10 {
  padding-top: 10px;
}

.dtech-push-right-flexbox {
  margin-left: auto;
}

/* bootstrap already has .text-a-c, better to use it instead of below */
.dtech-text-center {
  text-align: center;
}

.dtech-w-100p {
  width: 100%;
}

/* Compensate for Page Column having a margin: 5px */
.dtech-w-100vw-10px {
  width: calc(100vw - 10px);
}

/* Compensate for first child column being set to flex: .4 */
.dtech-w-100vw-40p {
  width: calc(100vw - 40%);
}

/* START - Updates for Count controls for Tasker Count widget and the properties page */
.dtech-filter-btn {
  align-items: center;
  height: 52px;
  background-color: rgba(255, 255, 255, 1);
  border-radius: 5px;
  box-shadow: 0px 1px 20px 0px rgba(0,0,0,0.15);
  padding:2px;
} 

/* sets border for disabled button*/
.dtech-filter-btn:disabled {
  border: 2px solid rgba(20, 146, 230, 1);
} 

.dtech-btn:hover{
  background-color: rgba(217, 237, 247, 1);
} 

/* sets the width for the filter text */
.dtech-filter-width-200 {
  min-width: 200px;
  padding-right: 10px;
}

.dtech-btn-focus {
  outline: 2px solid #66afe9;
}
/* END - Updates for Count controls for Tasker Count widget and the properties page */
